text:
/* Structural rules shared across the light and dark themes.
   Colour tokens live in theme-light.scss / theme-dark.scss. */

/* Button fill style (Turing-like) ---------------------------------------- */
.button--fill {
  background: var(--epi-primary, #0f7c8f);
  color: #fff !important;
  border: none;
}
.button--fill:hover {
  background: var(--epi-primary-dark, #0b5e6d);
  color: #fff !important;
}

.navbar-title { font-weight: 700; letter-spacing: 0.2px; }
.navbar-brand img { height: 30px; }

/* Headings a touch tighter for a cleaner, modern feel. */
h1, h2, h3 { letter-spacing: -0.02em; }

/* Section layout helpers (Turing-inspired) -------------------------------- */
.side-space {
  max-width: 1350px;
  margin-left: auto;
  margin-right: auto;
  padding-left: 4rem;
  padding-right: 4rem;
}
.section-start-space { padding-top: 2rem; }
.section-end-space { padding-bottom: 2rem; }
.section-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}
.section-header h3 {
  margin-bottom: 0;
}

/* Logo header */
.logo-header {
  padding: 0;
  margin-bottom: 0;
}

/* Hero (Turing-inspired) -------------------------------------------------- */
.hero-section {
  padding: 4rem 1rem;
  padding-bottom: 0%;
  text-align: center;
}
.hero-content {
  max-width: 800px;
  margin: 0 auto 3rem auto;
}
.hero-logo {
  max-width: 45%;
  height: auto;
  margin-bottom: 1.5rem;
  margin-left: auto;
  margin-right: auto;
}
.hero-subtitle {
  font-size: clamp(1.1rem, 3vw, 1.5rem);
  color: #46586b;
  margin-bottom: 2.5rem;
  max-width: 600px;
  margin-left: auto;
  margin-right: auto;
}

/* What is EpiAware Grid (Turing-inspired) -------------------------------- */
.what-is-turing-grid {
  display: grid;
  grid-template-columns: 1fr 1.25fr;
  gap: 3rem;
  align-items: center;
}
.feature-text-column {
  display: flex;
  flex-direction: column;
  gap: 2rem;
}
.feature-item-header {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  margin-bottom: 0.5rem;
}
.feature-item h5 {
  font-weight: 700;
  font-size: 1.2rem;
  margin-bottom: 0;
}
.feature-item p {
  font-size: 1rem;
  line-height: 1.6;
  margin-bottom: 0;
}
.feature-cta-button {
  margin-top: 2rem;
  text-align: center;
}
.btn-lg {
  padding: 14px 32px;
  font-size: 1.1rem;
}

